import React, { useState, useContext } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
//import PropTypes from 'prop-types';
import classNames from 'classnames';
import { NewsContext } from '../../NewsProvider';
import './Header.scss';
import { Categories } from '../Categories';

export const Header = () => {
  const [menu, setMenu] = useState(true);
  const {
    query,
    setQuery,
    applyQuery,
    setClick,
    setPath,
  } = useContext(NewsContext);
  // const [query, setQuery] = useState('');
  // const [appliedQuery, setAppliedQuery] = useState('');
  // const [value, setValue] = useState('');
  // const [categories, setCategories] = useState(false);
  const location = useLocation();
  console.log(location);
  // console.log(location.pathname);
  // const {pathname}
  // const [path, setPath] = useState(location.pathname);
  // const par = useRouteMatch.params;
  // console.log(match, par)
  // console.log(path, location.pathname);
  // const location = useLocation();
  // const searchParams = new URLSearchParams(location.search);
  // const applyiedQuery = searchParams.get('query') || '';
  // console.log(location, searchParams);

  return (
    <header className="Header" id="/articles">
      <div className="container-headerNav">
        <form className="Header-Form form">
          <button
            type="button"
            className="button-search"
            onClick={() => setQuery('')}
          />
          <input
            type="text"
            className="form-input"
            value={query}
            onChange={(e) => {
              setQuery(e.target.value);
              applyQuery(e.target.value);
            }}
            placeholder="Search..."
          />
          {query && (
            <button
              type="button"
              className="button-clear"
              onClick={() => {
                setQuery('');
                applyQuery('');
                setClick(false);
              }}
            >
              {}
            </button>
          )}
        </form>
        <div className="container-nav">
          <nav className="Header-Nav Nav">
            <NavLink
              to={location.pathname.includes('/home')
                ? `${location.pathname}${location.search}` || '/home'
                : '/home'}
              className="Nav-Link"
              onClick={() => {
                setPath('/home');
                setClick(false);
              }}
            >
              Home
            </NavLink>
            <NavLink
              to={location.pathname.includes('/articles')
                ? `${location.pathname}${location.search}` || '/articles'
                : '/articles'}
              className="Nav-Link"
              onClick={() => {
                setPath('/articles');
                setClick(false);
              }}
            >
              Articles
            </NavLink>
          </nav>
          <div className="container-links">
            <a href="http://insagram.com" className="Header-Instagram link">{}</a>
            <a href="http://twitter.com" className="Header-Twitter link">{}</a>
            <a href="http://linkedin.com" className="Header-LinkedIn link">{}</a>
          </div>
        </div>
      </div>
      <div className={classNames('container', {
        container_menu: menu,
      })}
      >
        <a
          className={classNames('Header-Logo', {
            logo_visible: !menu,
          })}
          href="/"
        >
          News App
        </a>

        <div className="Header-Menu Menu">
          <div className={classNames('container-category', {
            menu_visible: !menu,
          })}
          >
            <NavLink
              // to={`${path}/categories`}
              to={location.pathname.includes('categories')
                ? `${location.pathname}${location.search}`
                : `${location.pathname}/categories`}
              className="Menu-Link"
              onClick={() => <Categories />}
            >
              Categories
            </NavLink>
            {location.pathname.includes('categories') && <Categories />}
          </div>
          <button
            type="button"
            className={classNames('button-menu', {
              menu_open: menu,
              menu_cross: !menu,
            })}
            onClick={() => setMenu(!menu)}
          />
        </div>
      </div>
    </header>
  );
};

